INSERT INTO `blog_posts` (`id`, `title`, `content`, `slug`, `seo_title`, `seo_description`, `category_id`, `created_at`, `updated_at`) VALUES
('1', 'Motorbike Rentals Starting from £70 – Your Ultimate Ride Awaits!', '<p>Are you ready to hit the road and feel the wind in your hair? Whether you\'re planning an exciting city tour or an adventurous countryside ride, renting a motorbike is the perfect way to experience the freedom of the open road. At NGN, we\'re proud to offer top-quality motorbike rentals starting from just £70 per day, ensuring you can enjoy a thrilling ride without breaking the bank!</p><h4>Why Choose Us for Your Motorbike Rental?</h4><p><strong>Affordable Prices, Premium Experience</strong> Renting a motorbike doesn’t have to be expensive. With prices starting from £70, we provide a range of affordable options that don\'t compromise on quality or safety. From budget-friendly scooters to high-performance bikes, you\'ll find the perfect ride to match your adventure and budget.</p><p><strong>Wide Range of Motorbikes</strong> We offer a wide selection of motorbikes for every kind of rider. Whether you\'re looking for a nimble scooter for city commuting or a powerful cruiser for a weekend getaway, we\'ve got you covered. Our fleet includes:</p><ul><li><strong>Scooters and Urban Bikes</strong>: Perfect for city rides and short trips.</li><li><strong>Cruisers and Sport Bikes</strong>: Ideal for long-distance rides and thrilling adventures.</li><li><strong>Adventure and Touring Bikes</strong>: Designed for those who seek the thrill of exploring scenic routes and off-road terrains.</li></ul><p><strong>Well-Maintained Fleet</strong> Our motorbikes are regularly serviced and maintained to ensure you have a safe and enjoyable ride every time. We pride ourselves on offering bikes that are in top condition, so you can focus on enjoying your ride, not worrying about your bike’s performance.</p><p><strong>Flexible Rental Options</strong> We understand that every ride is different, which is why we offer flexible rental terms to suit your needs. Whether you’re looking to rent for a day, a weekend, or longer, we provide a range of options that allow you to enjoy the freedom of the road without the commitment of ownership.</p><p><strong>Convenient Locations</strong> Our rental locations are conveniently situated, making it easy for you to pick up your motorbike and start your adventure. Whether you\'re in the heart of the city or near scenic routes, we make sure you\'re never far from your next ride.</p><h4>How to Book Your Motorbike Rental</h4><p>Booking your motorbike rental with us is quick and easy! Simply follow these steps:</p><ol><li><strong>Visit Our Website</strong>: Browse our fleet of motorbikes and choose the one that suits your needs.</li><li><strong>Select Your Rental Dates</strong>: Pick your preferred rental duration and the dates you’d like to rent.</li><li><strong>Book and Pay</strong>: Complete the booking process online and secure your motorbike for your adventure.</li><li><strong>Pick Up Your Bike</strong>: On the day of your rental, come to our location and pick up your bike, ready to hit the road!</li></ol><h4>Why Rent a Motorbike?</h4><ul><li><strong>Freedom and Flexibility</strong>: Riding a motorbike gives you the freedom to explore places at your own pace. No need to wait for public transportation or follow rigid schedules.</li><li><strong>Cost-Effective Travel</strong>: Motorbikes are an affordable option compared to traditional car rentals. With lower fuel consumption and rental rates, you get great value for your money.</li><li><strong>Exciting Adventure</strong>: There’s nothing quite like the thrill of riding a motorbike. From the roar of the engine to the feeling of the open road, a motorbike ride is an experience you won’t forget.</li><li><strong>Eco-Friendly Option</strong>: Compared to cars, motorbikes consume less fuel and produce fewer emissions, making them a more environmentally friendly way to travel.</li></ul><h4>What’s Included in the Rental?</h4><p>When you rent a motorbike with us, you get more than just the bike itself. We provide everything you need for a safe and enjoyable ride:</p><ul><li><strong>Helmet</strong>: Safety is our priority, and we provide high-quality helmets for every rider.</li><li><strong>Insurance</strong>: Optional insurance packages are available for added peace of mind.</li><li><strong>24/7 Roadside Assistance</strong>: In the unlikely event of an issue, we offer 24/7 roadside assistance to ensure you’re never stranded.</li></ul><h4>Ready to Ride?</h4><p>Don\'t wait! Book your motorbike rental today and start your adventure for as little as £70. Whether you’re planning a solo ride, a weekend getaway with friends, or a romantic date with the open road, we’re here to provide you with the best motorbike rental experience.</p><p>For more information or to reserve your motorbike,give us a call at <a href=\"tel:02083141498\">0208 314 1498</a>. Your next adventure is just a ride away!</p>', 'motorbike-rentals-starting-from-libra70-your-ultimate-ride-awaits', 'motorbike-rentals-starting-from-libra70-your-ultimate-ride-awaits', 'Rent top-quality motorbikes starting at £70 for city tours, adventures, and weekend getaways. Flexible rental options, helmets, insurance, and 24/7 roadside assistance included for a safe, thrilling ride.', '1', '2025-02-01 18:02:20', '2025-02-01 18:02:20'),
('12', 'Ride Now, Pay Later!', '<p>At <strong>NGN Motors</strong>, we make it easier than ever to <strong>own a brand-new motorcycle.</strong> No need to wait—<strong>ride now and pay in easy monthly payments!</strong></p><p><strong>Why Choose Us?</strong></p><ul><li>✔ Low deposit options available</li><li>✔ Flexible repayment terms tailored to your budget</li><li>✔ Quick and hassle-free approval process</li></ul><p><strong>Top-Selling New Motorcycles Available:</strong></p><ul><li>✅ HONDA PCX 125</li><li>✅ YAMAHA X-MAX 125 ABS</li><li>✅ HONDA SH 125 AD-L</li><li>✅ HONDA CB 500 F</li></ul><p>Visit our showroom today, Ride home your dream bike without breaking the bank!</p>', 'ride-now-pay-later', 'Buy a New Motorcycle on Easy Instalments – Ride Now, Pay Later!', 'Get your dream motorcycle with our flexible instalment plans. Easy finance options available now at NGN Motors!', '8', '2025-02-25 16:12:54', '2025-06-27 16:15:58'),
('13', 'Premium Motorcycle Accessories – Upgrade Your Ride Today!', '<p>Enhance your motorbike with our <strong>wide range of premium motorcycle accessories</strong>. From safety gear to performance upgrades, <strong>NGN Motors</strong> has everything you need to customise your ride.</p><p><strong>Our Best-Selling Accessories:</strong></p><ul><li>✔ Helmet collection – Full-face, modular, and open-face designs</li><li>✔ Protective riding gear – Jackets, gloves, and boots</li><li>✔ Performance parts – Exhaust systems, air filters, and brake upgrades</li><li>✔ Security locks and alarms – Protect your bike from theft</li><li>✔ Luggage solutions – Top boxes, saddlebags, and tank bags</li></ul><p>Upgrade your motorcycle today with <strong>high-quality, road-tested accessories</strong> from <strong>NGN Motors</strong>!</p>', 'motorcycle-accessories-upgrade', 'Premium Motorcycle Accessories – Upgrade Your Ride Today!', 'Shop high-quality motorcycle accessories at NGN Motors. Helmets, riding gear, performance upgrades & more!', '3', '2025-02-25 16:12:54', '2025-02-25 17:26:13'),
('14', 'Motorcycle Tyres & Fitting Service – Get the Perfect Grip!', '<p>Your motorcycle’s tyres are the most critical safety feature. At <strong>NGN Motors</strong>, we provide <strong>top-quality tyres with professional fitting</strong> to ensure maximum grip and control on the road.</p><p><strong>Tyre Services Include:</strong></p><ul><li>✔ New tyre fitting for all motorcycle models</li><li>✔ Tyre balancing &amp; alignment</li><li>✔ Puncture repairs &amp; replacements</li><li>✔ Seasonal tyre recommendations for year-round performance</li></ul><p><strong>We Stock Leading Brands Like:</strong></p><ul><li>✅ Michelin</li><li>✅ Pirelli</li><li>✅ Dunlop</li><li>✅ Bridgestone</li></ul><p>Don’t compromise on safety—<strong>get your tyres checked or replaced today</strong> at <strong>NGN Motors</strong>!</p>', 'motorcycle-tyres-fitting-service', 'Motorcycle Tyres & Fitting Service – Get the Perfect Grip!', 'Get top-quality motorcycle tyres and professional fitting service at NGN Motors. Ensure your bike’s safety today!', '4', '2025-02-25 16:12:54', '2025-02-25 17:21:49'),
('15', 'Motorcycle Customisation & Modifications – Make It Uniquely Yours!', '<p>Looking to stand out on the road? At <strong>NGN Motors</strong>, we specialise in <strong>motorcycle customisation and modifications</strong> to enhance both aesthetics and performance.</p><p><strong>Customisation Services Include:</strong></p><ul><li>✔ Custom paintwork &amp; graphics</li><li>✔ LED lighting &amp; indicator upgrades</li><li>✔ Exhaust system enhancements</li><li>✔ Handlebar &amp; seat modifications for comfort &amp; style</li><li>✔ Performance tuning for increased power &amp; efficiency</li></ul><p>Transform your motorcycle into a true reflection of your personality. <strong>Visit NGN Motors today and customise your ride!</strong></p>', 'motorcycle-customisation-modifications', 'Motorcycle Customisation & Modifications – Make It Uniquely Yours!', 'Personalise your motorcycle with NGN Motors. Custom paint, LED lighting, performance tuning & more!', '5', '2025-02-25 16:12:54', '2025-02-25 17:22:11'),
('16', 'Breakdown Recovery Service – We’ve Got You Covered!', '<p>Stranded with a broken-down motorcycle? <strong>NGN Motors’ Breakdown Recovery Service</strong> ensures <strong>fast and reliable assistance</strong> whenever you need it.</p><p><strong>Why Choose NGN Recovery?</strong></p><ul><li>✔ 24/7 emergency support across London &amp; surrounding areas</li><li>✔ Fast response times to get you back on the road quickly</li><li>✔ Transport to the nearest repair centre or your home</li><li>✔ Affordable rates with no hidden charges</li></ul><p>Whether its a <strong>flat battery, tyre puncture, or engine failure</strong>, our team is here to help. <strong>Call NGN Motors for emergency motorcycle recovery today!</strong></p>', 'motorcycle-breakdown-recovery-service', 'Breakdown Recovery Service – We’ve Got You Covered!', 'Stranded? Get fast & reliable motorcycle breakdown recovery from NGN Motors. 24/7 service in London!', '6', '2025-02-25 16:12:54', '2025-02-25 17:18:09'),
('17', 'Why Your Next Ride Should Be Electric – Discover the Power of NGN E-Bikes', '<p>Thinking about upgrading your ride? There’s never been a better time to make the switch to electric. At <strong>NGN Motors</strong>, we’re excited to introduce our brand-new line of <strong>E-Bikes</strong>, engineered for modern urban commuting, eco-conscious travel, and electrifying performance.</p><p>Whether you\'re commuting through the city, exploring backroads, or just enjoying the freedom of two wheels – our E-Bikes are built to transform your riding experience.</p><h3>⚡ <strong>Why Choose NGN E-Bikes?</strong></h3><p>✔ <strong>Zero Emissions, Maximum Efficiency</strong></p><p>✔ <strong>Smart Performance</strong></p><p>✔ <strong>Stylish &amp; Sleek Design</strong></p><p>✔ <strong>Low Maintenance, High Convenience</strong></p><p>✔ <strong>Quiet Power</strong></p><h3>🚀 <strong>Now Launching – Limited Introductory Offers Available</strong></h3><p>Be among the first to experience the future of riding. Our E-Bikes are launching this summer – and trust us, you don’t want to miss it.</p><p><strong>NGN Motors – Ride Electric. Ride Smarter.</strong></p>', 'why-your-next-ride-should-be-electric-discover-the-power-of-ngn-e-bikes', 'E-Bikes Rental, Buy, New, and Used in London, Tooting, Sutton.', 'Buy or rent the best e-bikes in London at affordable prices. Available in Sutton, Catford, and across London. Quality electric bikes with unbeatable value!', '1', '2025-06-14 16:59:06', '2025-06-27 13:57:52');
